// Añadido: sección "Extracción asistida por IA (opcional)" — commit "feat: añade extracción asistida
// por IA (flujo copia-pega, procesamiento cliente, sin envío a servidores)".
// Reemplazado: flujo de un solo paso BYOK (llamada directa navegador→proveedor de IA con clave propia
// del usuario) — commit "feat: extracción con IA en un solo paso (BYOK, sin backend)". El flujo copia-pega
// original se conserva íntegro como "modo manual (fallback)", oculto tras un enlace. Ver ai-extraction.mjs
// (esquema/prompt/validación, reutilizados sin cambios), ai-providers.mjs (llamada HTTP BYOK) y
// key-storage.mjs (cifrado AES-GCM opcional de la clave + consentimiento).
import{DIMENSIONS,MODEL_VERSION,VARIABLES,cumulativeInterventions,scoreCase,exportCsv,exportJson,importJson,printableReport}from'./core.mjs';
import{buildPrompt,parseExtractionResponse,validateExtraction}from'./ai-extraction.mjs';
import{PROVIDERS,callProvider}from'./ai-providers.mjs';
import{hasStoredKey,getStoredConfig,clearStoredKey,encryptAndStoreKey,decryptStoredKey,getConsent,setConsent,revokeConsent}from'./key-storage.mjs';
const KEY='cmo_migrana_cases_v1';
let id=crypto.randomUUID(),pseudonym='CASO-'+Math.random().toString(36).slice(2,7).toUpperCase(),hospital='',pharmacist='',answers={},override;
// Estado de la extracción asistida por IA: SOLO en memoria (nunca en localStorage/sessionStorage/IndexedDB/cookies),
// salvo la clave API si el usuario elige explícitamente "recordar en este navegador" (entonces se guarda
// cifrada, ver key-storage.mjs). Se reinicia al borrar la extracción, al recuperar otro caso o al importar un caso.
let iaOpen=false,iaHcText='',iaPrompt='',iaJsonText='',iaFilledVarIds=new Set(),iaCitations={},iaValidationReport=null;
let aiConfigOpen=false,aiManualOpen=false,aiBusy=false,aiLastError=null,aiExtractionSummary=null,aiUnlockError=null,aiSaveKeyNotice=null;
let aiProvider='azure',aiModel=PROVIDERS.azure.defaultModel,aiEndpoint='',aiApiKey='',aiRememberMode='session',aiKeyVisible=false;
let aiConsentPending=false,aiConsentAccepted=!!(getConsent()&&getConsent().accepted);
function resetIaExtraction(revertAnswers){if(revertAnswers)iaFilledVarIds.forEach(vid=>{delete answers[vid]});iaHcText='';iaPrompt='';iaJsonText='';iaFilledVarIds=new Set();iaCitations={};iaValidationReport=null;aiExtractionSummary=null;aiLastError=null}
const $=s=>document.querySelector(s);
const esc=s=>String(s??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
function loadCases(){return JSON.parse(localStorage.getItem(KEY)||'[]')}
function save(){const cases=loadCases().filter(c=>c.id!==id);cases.unshift({id,pseudonym,hospital,pharmacist,answers,override,updatedAt:new Date().toISOString(),trace:[{at:new Date().toISOString(),action:'autosave'}]});localStorage.setItem(KEY,JSON.stringify(cases))}
function dl(n,t,type='application/json'){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([t],{type}));a.download=n;a.click()}

function modelFieldHtml(meta){
if(meta.modelKind==='text')return`<label>${esc(meta.modelFieldLabel)}<input id="aiModelInput" value="${esc(aiModel)}" placeholder="nombre-de-mi-deployment"></label>`;
const isCustom=!meta.modelOptions.includes(aiModel);
return`<label>${esc(meta.modelFieldLabel)}<select id="aiModelSelect">${meta.modelOptions.map(m=>`<option value="${m}" ${aiModel===m?'selected':''}>${m}</option>`).join('')}<option value="__other__" ${isCustom?'selected':''}>Otro (especificar)…</option></select></label>${isCustom?`<label>Modelo personalizado<input id="aiModelCustom" value="${esc(aiModel)}" placeholder="id-del-modelo"></label>`:''}`}

function consentModalHtml(){const meta=PROVIDERS[aiProvider];
return`<div class="modal-backdrop"><div class="modal" role="dialog" aria-modal="true" aria-label="Aviso de uso de IA con datos clínicos"><h2>AVISO — Uso de IA con datos clínicos</h2><p>Al pulsar 'Extraer y prerrellenar', el texto que ha pegado se enviará al proveedor de IA configurado (<b>${esc(meta.label)}</b>) usando su clave API personal.</p><ul><li>Confirme que ha eliminado TODO dato identificativo del paciente antes de pegar.</li><li>Use únicamente el proveedor de IA autorizado por su centro para tratamiento de datos clínicos, aunque estén anonimizados.</li><li>La responsabilidad del uso, del cumplimiento normativo (RGPD/LOPDGDD) y del contrato con el proveedor es del usuario y de su institución.</li><li>La herramienta no almacena el texto pegado ni la respuesta en ningún servidor externo. Todo el procesamiento local ocurre en su navegador.</li></ul><p><small>Autor: Ramón Morillo-Verdugo (julio 2026). Sin ánimo comercial.</small></p><div class="modal-actions"><button id="consentAccept" type="button">He leído y acepto</button><button id="consentCancel" type="button" class="btn-secondary">Cancelar</button></div></div></div>`}

function aiConfigPanelHtml(){const meta=PROVIDERS[aiProvider];const stored=hasStoredKey();
return`<div class="ia-config" id="aiConfigPanel"><h3>Configuración del proveedor de IA</h3><label>Proveedor<select id="aiProviderSelect">${Object.values(PROVIDERS).map(p=>`<option value="${p.id}" ${aiProvider===p.id?'selected':''}>${esc(p.label)}</option>`).join('')}</select></label>${meta.needsEndpoint?`<label>Endpoint del deployment institucional<input id="aiEndpointInput" value="${esc(aiEndpoint)}" placeholder="${esc(meta.endpointPlaceholder)}"></label><small class="ia-note">${esc(meta.endpointHelp)}</small>`:''}${modelFieldHtml(meta)}<label>Clave API<div class="ia-key-row"><input id="aiApiKeyInput" type="${aiKeyVisible?'text':'password'}" value="${esc(aiApiKey)}" placeholder="Clave API personal"><button id="aiKeyToggle" type="button">${aiKeyVisible?'Ocultar':'Mostrar'}</button></div></label><fieldset class="ia-remember"><legend>Guardar la clave</legend><label><input type="radio" name="aiRemember" value="session" ${aiRememberMode==='session'?'checked':''}> Solo esta sesión (se pierde al cerrar la pestaña)</label><label><input type="radio" name="aiRemember" value="local" ${aiRememberMode==='local'?'checked':''}> Recordar en este navegador (cifrado con una frase de paso)</label></fieldset>${aiRememberMode==='local'?`<label>Frase de paso para cifrar<input id="aiPassphraseInput" type="password" placeholder="Frase de paso (no se guarda)"></label><button id="saveKeyBtn" type="button">Guardar clave cifrada</button>`:''}${stored?`<p class="ia-note">Hay una clave guardada cifrada en este navegador.</p><label>Frase de paso para desbloquear<input id="aiUnlockPassphrase" type="password" placeholder="Frase de paso"></label><button id="unlockKeyBtn" type="button">Desbloquear clave guardada</button><button id="clearKeyBtn" type="button">Borrar clave guardada</button>`:''}${aiUnlockError?`<p class="alert">${esc(aiUnlockError)}</p>`:''}${aiSaveKeyNotice?`<p class="progress">${esc(aiSaveKeyNotice)}</p>`:''}${aiConsentAccepted?`<button id="aiRevokeConsent" type="button">Revocar consentimiento</button>`:''}<p><a href="#" id="aiHelpLink">¿Cómo obtener una clave API? Consulte con su servicio de informática.</a></p></div>`}

function extractButtonHtml(){return aiBusy?`<button id="extractBtn" type="button" disabled class="ia-busy"><span class="spinner" aria-hidden="true"></span> Extrayendo... esto puede tardar 5-15 segundos</button>`:`<button id="extractBtn" type="button">Extraer y prerrellenar cuestionario</button>`}

function errorBlockHtml(){if(!aiLastError)return'';return`<p class="alert">${esc(aiLastError.message)}</p><button id="useManualFallback" type="button">Usar modo manual (fallback)</button>`}

function extractionSummaryHtml(){if(!aiExtractionSummary)return'';const r=aiExtractionSummary;const list=r.notFoundDeclared.length?r.notFoundDeclared.join(', '):'ninguno';return`<p class="${r.problems.length?'alert':'progress'}">Se han extraído ${r.filledCount} de ${r.totalExpected} campos. Campos no encontrados: ${esc(list)}. Revise antes de calcular la estratificación.${r.problems.length?` ${r.problems.length} campo(s) con incidencia de formato: ${r.problems.map(p=>`${esc(p.label||p.id||'JSON')} (${esc(p.issue)})`).join('; ')}.`:''}</p>`}

function manualFallbackHtml(){const promptBlock=iaPrompt?`<pre class="ia-prompt"><code>${esc(iaPrompt)}</code></pre><button id="copyPrompt" type="button">Copiar prompt completo al portapapeles</button><p class="ia-note">Pegue este prompt en el LLM corporativo autorizado por su centro (Copilot, ChatGPT Enterprise, Gemini u otro validado por su servicio de farmacia). NO use LLMs públicos gratuitos con datos clínicos, aunque estén anonimizados.</p>`:'<p class="ia-note">Pulse «Generar prompt para IA» tras pegar el texto de la historia clínica.</p>';
const reportBlock=!iaValidationReport?'':iaValidationReport.parseError?`<p class="alert">El texto pegado no es un JSON válido: ${esc(iaValidationReport.message)}. Puede corregirlo y volver a intentarlo, o completar el cuestionario manualmente; la herramienta sigue funcionando con normalidad.</p>`:`<p class="${iaValidationReport.problems.length?'alert':'progress'}">Extracción IA: ${iaValidationReport.filledCount}/${iaValidationReport.totalExpected} campos completados automáticamente.${iaValidationReport.notFoundDeclared.length?` La IA declaró ${iaValidationReport.notFoundDeclared.length} campo(s) como no encontrados en la historia clínica.`:''}${iaValidationReport.problems.length?` ${iaValidationReport.problems.length} campo(s) con incidencia — complete manualmente: ${iaValidationReport.problems.map(p=>`${esc(p.label||p.id||'formato JSON')} (${esc(p.issue)})`).join('; ')}.`:' Sin incidencias de formato.'}</p>`;
return`<div class="ia-manual" id="iaManualBlock"><p class="ia-note">Modo manual (fallback): use este flujo de copia-pega si su centro no permite llamadas directas a la API del proveedor de IA. Reutiliza el mismo texto de historia clínica pegado más arriba.</p><button id="genPrompt" type="button">Generar prompt para IA</button>${promptBlock}<label>JSON devuelto por el LLM corporativo<textarea id="iaJson" rows="8" placeholder='{"situacion_reproductiva": null, "...": "...", "campos_no_encontrados": [], "citas_textuales": {}}'>${esc(iaJsonText)}</textarea></label><button id="validateJson" type="button">Validar y rellenar cuestionario</button>${reportBlock}</div>`}

function iaSectionHtml(){const meta=PROVIDERS[aiProvider];
return`<section class="panel ia-panel"><details id="iaDetails" ${iaOpen?'open':''}><summary>Extracción asistida por IA (opcional)</summary><button id="aiConfigToggle" type="button" class="icon-btn" title="Configurar proveedor de IA">⚙️</button><div class="ia-body"><p class="warning">⚠️ IMPORTANTE — Antes de pegar: elimine cualquier dato identificativo del paciente (nombre, apellidos, NHC, DNI, fecha de nacimiento exacta, dirección, teléfono).</p><p class="warning ia-send-warning">📡 El texto se envía a <b>${esc(meta.label)}</b> al pulsar el botón. Anonimice antes de pegar.</p>${aiConfigOpen?aiConfigPanelHtml():''}<label>Texto libre pegado desde la historia clínica electrónica<textarea id="hcText" rows="8" placeholder="Pegue aquí el texto del evolutivo/HC ya anonimizado por usted...">${esc(iaHcText)}</textarea></label>${extractButtonHtml()}${errorBlockHtml()}${extractionSummaryHtml()}<p><a href="#" id="manualModeLink">${aiManualOpen?'Ocultar modo manual (fallback)':'Modo manual (fallback): generar prompt para copiar / pegar JSON manualmente'}</a></p>${aiManualOpen?manualFallbackHtml():''}<button id="resetIa" type="button">Borrar todos los datos de esta extracción</button></div></details></section>`}

function requestExtraction(){if(aiBusy)return;
if(!iaHcText.trim()){alert('Pegue primero el texto de la historia clínica anonimizada.');return}
if(!aiApiKey){alert('Configure una clave API en el panel ⚙️ antes de extraer.');aiConfigOpen=true;render();return}
const meta=PROVIDERS[aiProvider];
if(meta.needsEndpoint&&!aiEndpoint.trim()){alert('Indique el endpoint del deployment en el panel ⚙️.');aiConfigOpen=true;render();return}
if(!aiModel||!String(aiModel).trim()){alert('Indique el modelo o el nombre del deployment en el panel ⚙️.');aiConfigOpen=true;render();return}
if(!aiConsentAccepted){aiConsentPending=true;render();return}
runExtraction()}

async function runExtraction(){aiBusy=true;aiLastError=null;aiExtractionSummary=null;render();
const userPrompt=buildPrompt(iaHcText);
const system='Eres un asistente clínico de extracción estructurada para un cuestionario de estratificación CMO en migraña. Responde EXCLUSIVAMENTE con un objeto JSON válido, sin texto adicional ni bloques de código markdown.';
const baseArgs={provider:aiProvider,apiKey:aiApiKey,endpoint:aiEndpoint,model:aiModel,system};
try{let raw=await callProvider({...baseArgs,messages:[{role:'user',content:userPrompt}]});let parsed;
try{parsed=parseExtractionResponse(raw)}
catch{raw=await callProvider({...baseArgs,messages:[{role:'user',content:userPrompt},{role:'assistant',content:raw},{role:'user',content:'La respuesta anterior no era JSON válido. Devuelve exclusivamente un JSON válido, sin texto adicional, sin markdown.'}]});
try{parsed=parseExtractionResponse(raw)}catch{throw new Error('La IA no devolvió un JSON válido tras dos intentos. Puede reintentar o usar el modo manual (fallback).')}}
const rep=validateExtraction(parsed);for(const[k,v]of Object.entries(rep.filled)){answers[k]=v;iaFilledVarIds.add(k)}iaCitations={...iaCitations,...rep.citations};aiExtractionSummary=rep;save()}
catch(e){aiLastError={message:e.message||'Error inesperado al conectar con el proveedor de IA.'}}
aiBusy=false;render()}

function render(){const r=scoreCase(answers,override);const completed=VARIABLES.length-r.missing.length;document.title=`CMO-Migraña P${r.finalPriority}`;$('#app').innerHTML=`${aiConsentPending?consentModalHtml():''}<header class="hero"><div class="hero__content"><span class="badge">🏥 ${MODEL_VERSION}</span><h1>SIAF-CMO Migraña</h1><p class="subtitle">Sistema inteligente de atención farmacéutica para estratificar, priorizar y documentar pacientes con migraña.</p><p class="warning">Herramienta de apoyo a la estratificación y planificación farmacéutica. No sustituye el juicio clínico, no diagnostica, no prescribe, no recomienda cambios autónomos de tratamiento, no es producto sanitario certificado y debe validarse antes de implantación asistencial.</p><div class="chips"><span>CMO: Capacidad–Motivación–Oportunidad</span><span>IA responsable</span><span>Decisión final profesional</span></div></div><aside class="ecosystem" aria-label="Estado del caso"><h2>Estado de la valoración</h2><div class="metrics"><div><b>${completed}</b><span>variables completadas</span></div><div><b>${r.finalPriority}</b><span>prioridad final</span></div><div><b>${r.total}/40</b><span>puntuación</span></div><div><b>${r.missing.length}</b><span>pendientes</span></div></div><div class="ecosystem__tags"><span>MAPEX-SEFH</span><span>Práctica clínica</span><span>Informe</span></div></aside></header><section class="panel identity"><h2>1. Identificación de uso e institución</h2><div class="grid two"><label>Identificación pseudonimizada<input id="pseudo" value="${esc(pseudonym)}"></label><label>Hospital / centro sanitario<input id="hospital" value="${esc(hospital)}" placeholder="Ej. Hospital Universitario..."></label><label>Farmacéutico/a responsable<input id="pharmacist" value="${esc(pharmacist)}" placeholder="Nombre y apellidos"></label><label>Buscar casos locales<input id="search" placeholder="Buscar por pseudónimo"></label></div><div id="cases" class="case-list"></div></section>${iaSectionHtml()}<section class="panel"><h2>2. Formulario por dimensiones</h2><p class="progress">Progreso: <b>${completed}/${VARIABLES.length}</b>. Los datos ausentes se muestran como pendientes y no se interpretan silenciosamente como cero.</p>${Object.entries(DIMENSIONS).map(([dim,d])=>`<fieldset><legend>${d.label} — subtotal ${r.subtotals[dim]}/${d.max}</legend>${VARIABLES.filter(v=>v.dimension===dim).map(v=>`<div class="card${iaFilledVarIds.has(v.id)?' card--ia':''}"><label>${v.label}${iaFilledVarIds.has(v.id)?` <span class="ia-tag" title="${esc(iaCitations[v.id]||'Procedente de extracción asistida por IA')}">IA — revisar</span>`:''}<select aria-label="${v.label}" data-var="${v.id}" class="${iaFilledVarIds.has(v.id)?'ia-filled':''}"><option value="">Pendiente</option>${v.options.map(o=>`<option value="${o.id}" ${answers[v.id]===o.id?'selected':''}>${o.label} — ${o.score} puntos</option>`).join('')}</select></label><details><summary>Definición y fuente</summary><p>${v.definition}</p><ul>${v.options.map(o=>`<li><b>${o.label}:</b> ${o.definition} (${o.score} puntos)</li>`).join('')}</ul><small>${v.sourcePage}</small></details></div>`).join('')}</fieldset>`).join('')}</section><section class="panel"><h2>3. Resumen y resultado</h2><div class="report-meta"><span><b>Hospital:</b> ${esc(hospital)||'Pendiente'}</span><span><b>Farmacéutico/a:</b> ${esc(pharmacist)||'Pendiente'}</span></div>${r.pediatric?'<p class="alert">Menor de 18 años: Requiere valoración mediante modelo pediátrico. No se presenta clasificación adulta como clínicamente válida.</p>':''}${r.missing.length?`<p class="alert">Cálculo provisional: variables pendientes ${r.missing.join(', ')}.</p>`:''}<div class="priority p${r.finalPriority}"><b>Prioridad final: ${r.finalPriority}</b><br>Prioridad calculada: ${r.algorithmPriority}; prioridad numérica: ${r.numericPriority}; puntuación ${r.total}/40.</div>${r.automaticPriority?`<p>Prioridad automática: Sí. Motivo: ${r.automaticPriorityReasons.join(', ')}.</p>`:''}<h3>Contribuciones</h3><table><thead><tr><th>Variable</th><th>Opción</th><th>Puntos</th></tr></thead><tbody>${r.contributions.map(c=>`<tr><td>${c.variable}</td><td>${c.option??'Pendiente'}</td><td>${c.score??'Sin dato'}</td></tr>`).join('')}</tbody></table><h3>Override clínico</h3><select id="override" aria-label="Nueva prioridad manual"><option value="">Sin modificación manual</option><option value="1">Prioridad 1</option><option value="2">Prioridad 2</option><option value="3">Prioridad 3</option></select>${override?`<p>Modificación manual: ${override.from} → ${override.to}. Justificación: ${override.justification}. Fecha: ${override.createdAt}. Decisión profesional ajena al algoritmo original.</p>`:''}<h3>Plan de seguimiento</h3><b>Reaplicación del modelo</b><ul>${r.periodicity.model.map(x=>`<li>${x}</li>`).join('')}</ul><b>Visitas de seguimiento</b><ul>${r.periodicity.followUp.map(x=>`<li>${x}</li>`).join('')}</ul><h3>Actuaciones farmacéuticas acumulativas</h3><ul>${cumulativeInterventions(r.finalPriority).map(i=>`<li><b>P${i.priority} · ${i.category}:</b> ${i.text}</li>`).join('')}</ul></section><section class="panel actions"><h2>4. Guardado, exportación, importación e impresión</h2><button id="save">Guardar caso</button><button id="json">Exportar JSON</button><button id="csv">Exportar CSV</button><button id="import">Importar JSON</button><button id="report">Descargar resumen clínico</button><button id="print">Imprimir informe</button><button id="del">Borrar caso</button><button id="clear">Borrar todos los datos</button></section><footer><b>Creada por Ramón Morillo Verdugo en julio de 2026.</b> Aplicación local privacy-first: sin analítica, sin APIs clínicas externas y sin envío intencionado de datos a servidores. Uso exclusivo como soporte profesional sanitario, con pseudonimización de datos, verificación clínica local, cumplimiento de RGPD/LOPDGDD, confidencialidad asistencial, registro responsable, revisión ética y validación previa a cualquier implantación asistencial.</footer>`;$('#pseudo').oninput=e=>{pseudonym=e.target.value;save()};$('#hospital').oninput=e=>{hospital=e.target.value;save()};$('#pharmacist').oninput=e=>{pharmacist=e.target.value;save()};document.querySelectorAll('[data-var]').forEach(x=>x.onchange=e=>{answers[e.target.dataset.var]=e.target.value||undefined;iaFilledVarIds.delete(e.target.dataset.var);save();render()});$('#override').onchange=e=>{const to=+e.target.value;if(to){const rr=scoreCase(answers);const justification=prompt('Justificación clínica obligatoria')||'';if(justification.trim()){override={from:rr.algorithmPriority,to,justification,createdAt:new Date().toISOString(),reinforcedWarningAccepted:!!(rr.automaticPriority&&to>rr.algorithmPriority)};save();render()}}};$('#save').onclick=()=>{save();alert('Caso guardado')};$('#json').onclick=()=>dl('caso-cmo-migrana.json',exportJson({id,pseudonym,hospital,pharmacist,answers,override,result:r}));$('#csv').onclick=()=>dl('caso-cmo-migrana.csv',exportCsv([{id,pseudonym,hospital,pharmacist,total:r.total,prioridad:r.finalPriority,status:r.status}]),'text/csv');$('#import').onclick=()=>{const text=prompt('Pegue JSON importado');if(text){const c=importJson(text);id=c.id||crypto.randomUUID();pseudonym=c.pseudonym||'CASO-IMPORTADO';hospital=c.hospital||'';pharmacist=c.pharmacist||'';answers=c.answers||{};override=c.override;resetIaExtraction(false);save();render()}};$('#report').onclick=()=>dl('informe-cmo-migrana.txt',printableReport({pseudonym,hospital,pharmacist,answers,override}),'text/plain');$('#print').onclick=()=>print();$('#del').onclick=()=>{if(confirm('¿Borrar este caso?')){localStorage.setItem(KEY,JSON.stringify(loadCases().filter(c=>c.id!==id)));alert('Borrado')}};$('#clear').onclick=()=>confirm('¿Borrar todos los datos locales?')&&localStorage.removeItem(KEY);$('#search').oninput=e=>{$('#cases').innerHTML=loadCases().filter(c=>c.pseudonym.toLowerCase().includes(e.target.value.toLowerCase())).slice(0,5).map(c=>`<button data-load="${c.id}">Recuperar ${esc(c.pseudonym)}</button>`).join('');document.querySelectorAll('[data-load]').forEach(b=>b.onclick=()=>{const c=loadCases().find(x=>x.id===b.dataset.load);id=c.id;pseudonym=c.pseudonym;hospital=c.hospital||'';pharmacist=c.pharmacist||'';answers=c.answers;override=c.override;resetIaExtraction(false);render()})};
$('#hcText').oninput=e=>{iaHcText=e.target.value};
$('#iaDetails').ontoggle=e=>{iaOpen=e.target.open};
$('#aiConfigToggle').onclick=e=>{e.preventDefault();e.stopPropagation();aiConfigOpen=!aiConfigOpen;aiUnlockError=null;aiSaveKeyNotice=null;render()};
$('#extractBtn').onclick=()=>requestExtraction();
if($('#useManualFallback'))$('#useManualFallback').onclick=()=>{aiManualOpen=true;if(iaHcText.trim())iaPrompt=buildPrompt(iaHcText);iaOpen=true;render()};
$('#manualModeLink').onclick=e=>{e.preventDefault();aiManualOpen=!aiManualOpen;render()};
if($('#consentAccept'))$('#consentAccept').onclick=()=>{setConsent(true);aiConsentAccepted=true;aiConsentPending=false;render();runExtraction()};
if($('#consentCancel'))$('#consentCancel').onclick=()=>{aiConsentPending=false;render()};
if($('#aiProviderSelect'))$('#aiProviderSelect').onchange=e=>{aiProvider=e.target.value;const meta=PROVIDERS[aiProvider];aiModel=meta.defaultModel;if(!meta.needsEndpoint)aiEndpoint='';render()};
if($('#aiEndpointInput'))$('#aiEndpointInput').oninput=e=>{aiEndpoint=e.target.value};
if($('#aiModelInput'))$('#aiModelInput').oninput=e=>{aiModel=e.target.value};
if($('#aiModelSelect'))$('#aiModelSelect').onchange=e=>{aiModel=e.target.value==='__other__'?'':e.target.value;render()};
if($('#aiModelCustom'))$('#aiModelCustom').oninput=e=>{aiModel=e.target.value};
if($('#aiApiKeyInput'))$('#aiApiKeyInput').oninput=e=>{aiApiKey=e.target.value};
if($('#aiKeyToggle'))$('#aiKeyToggle').onclick=()=>{aiKeyVisible=!aiKeyVisible;render()};
document.querySelectorAll('input[name="aiRemember"]').forEach(radio=>radio.onchange=e=>{aiRememberMode=e.target.value;aiSaveKeyNotice=null;render()});
if($('#saveKeyBtn'))$('#saveKeyBtn').onclick=async()=>{const passInput=$('#aiPassphraseInput');const passphrase=passInput?passInput.value:'';if(!aiApiKey){alert('Escriba primero la clave API a guardar.');return}try{await encryptAndStoreKey(aiApiKey,passphrase,{provider:aiProvider,model:aiModel,endpoint:aiEndpoint});aiSaveKeyNotice='Clave guardada cifrada correctamente en este navegador.';aiUnlockError=null}catch(e){alert(e.message||'No se pudo guardar la clave.')}if(passInput)passInput.value='';render()};
if($('#unlockKeyBtn'))$('#unlockKeyBtn').onclick=async()=>{const passInput=$('#aiUnlockPassphrase');const passphrase=passInput?passInput.value:'';try{aiApiKey=await decryptStoredKey(passphrase);const cfg=getStoredConfig();if(cfg){if(cfg.provider)aiProvider=cfg.provider;if(cfg.model)aiModel=cfg.model;if(cfg.endpoint)aiEndpoint=cfg.endpoint}aiRememberMode='local';aiUnlockError=null;aiSaveKeyNotice='Clave recuperada correctamente.'}catch(e){aiUnlockError=e.message}render()};
if($('#clearKeyBtn'))$('#clearKeyBtn').onclick=()=>{if(confirm('¿Borrar la clave API guardada en este navegador?')){clearStoredKey();aiSaveKeyNotice='Clave guardada eliminada de este navegador.';render()}};
if($('#aiRevokeConsent'))$('#aiRevokeConsent').onclick=()=>{revokeConsent();aiConsentAccepted=false;render()};
if($('#aiHelpLink'))$('#aiHelpLink').onclick=e=>{e.preventDefault();alert('Consulte con el servicio de informática de su centro cómo obtener y autorizar una clave API institucional para este proveedor.')};
if($('#genPrompt'))$('#genPrompt').onclick=()=>{if(!iaHcText.trim()){alert('Pegue primero el texto de la historia clínica anonimizada.');return}iaPrompt=buildPrompt(iaHcText);iaOpen=true;render()};
if($('#copyPrompt'))$('#copyPrompt').onclick=async()=>{const btn=$('#copyPrompt');const original=btn.textContent;try{await navigator.clipboard.writeText(iaPrompt)}catch{const ta=document.createElement('textarea');ta.value=iaPrompt;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta)}btn.textContent='Copiado ✓';setTimeout(()=>{if($('#copyPrompt'))$('#copyPrompt').textContent=original},1800)};
if($('#iaJson'))$('#iaJson').oninput=e=>{iaJsonText=e.target.value};
if($('#validateJson'))$('#validateJson').onclick=()=>{if(!iaJsonText.trim()){alert('Pegue primero el JSON devuelto por la IA.');return}let parsed;try{parsed=parseExtractionResponse(iaJsonText)}catch(e){iaValidationReport={parseError:true,message:e.message};iaOpen=true;render();return}const rep=validateExtraction(parsed);for(const[k,v]of Object.entries(rep.filled)){answers[k]=v;iaFilledVarIds.add(k)}iaCitations={...iaCitations,...rep.citations};iaValidationReport=rep;iaOpen=true;save();render()};
$('#resetIa').onclick=()=>{if(confirm('¿Borrar el texto de HC, el prompt, el JSON y los campos auto-rellenados de esta extracción de IA?')){resetIaExtraction(true);iaOpen=true;save();render()}}}
render();save();
